INSERT INTO transfer_outgoing VALUES(1,'2026-summer',3,'Arsenal','MEDIUM','아르테타 주도, 아스널이 콘사에 관심. 빌라는 £60m 밸류에이션 — 아스널은 고평가로 판단, 아직 오퍼 없음.','https://www.telegraph.co.uk (Arsenal Ezri Konsa interest, 2026-07-03)','HIGH — Telegraph(2티어) 단독 관심 보도. 협상/합의 단계 아님.');
INSERT INTO transfer_outgoing VALUES(2,'2026-summer',13,'Arsenal','MEDIUM-HIGH','£130m(요구)/£80m(청취 가능) 밸류. Sky Sports Paper Talk + Football365: 아스날 ''all in'', 첼시도 관심. 2031년까지 계약이라 빌라는 매각 압박 없음.','https://www.skysports.com/football/transfer-paper-talk (Sky Sports), https://www.football365.com/news/arsenal-new-asking-price-morgan-rogers-gunners-all-in-aston-villa-star','2티어+ 복수 보도로 상향 (기존 MEDIUM→MEDIUM-HIGH), 2026-07-07 확인');
